using System;

static string Classify(int n) => n switch {
    < 0  => "negative",
    0    => "zero",
    < 10 => "small positive",
    _    => "large positive"
};

class Program {
    static void Main() {
        foreach (int n in new[] { -5, 0, 3, 100 })
            Console.WriteLine($"{n}: {Classify(n)}");
    }
}

using System;

static string Describe(object obj) => obj switch {
    int n when n < 0  => $"negative int: {n}",
    int n             => $"positive int: {n}",
    string s          => $"string of length {s.Length}",
    null              => "null",
    _                 => $"unknown: {obj.GetType().Name}"
};

class Program {
    static void Main() {
        Console.WriteLine(Describe(-5));
        Console.WriteLine(Describe(42));
        Console.WriteLine(Describe("hello"));
        Console.WriteLine(Describe(null));
        Console.WriteLine(Describe(3.14));
    }
}

using System;

record Point(int X, int Y);

static string Quadrant(Point p) => p switch {
    { X: > 0, Y: > 0 } => "Q1",
    { X: < 0, Y: > 0 } => "Q2",
    { X: < 0, Y: < 0 } => "Q3",
    { X: > 0, Y: < 0 } => "Q4",
    { X: 0 } or { Y: 0 } => "on axis",
    _ => "origin"
};

class Program {
    static void Main() {
        Console.WriteLine(Quadrant(new Point(3, 4)));
        Console.WriteLine(Quadrant(new Point(-1, 2)));
        Console.WriteLine(Quadrant(new Point(0, 5)));
    }
}

using System;

static string RockPaperScissors(string a, string b) => (a, b) switch {
    ("Rock",     "Scissors") => $"{a} wins",
    ("Scissors", "Paper")   => $"{a} wins",
    ("Paper",    "Rock")    => $"{a} wins",
    (var x, var y) when x == y => "Tie",
    _ => $"{b} wins"
};

class Program {
    static void Main() {
        Console.WriteLine(RockPaperScissors("Rock", "Scissors"));
        Console.WriteLine(RockPaperScissors("Paper", "Paper"));
        Console.WriteLine(RockPaperScissors("Scissors", "Rock"));
    }
}

using System;

record Person(string Name, int Age);

class Program {
    static void Main() {
        var p = new Person("Alice", 30);
        var (name, age) = p; // deconstruct
        Console.WriteLine($"{name} is {age}");

        // Also works with tuples
        (int x, int y) = (10, 20);
        Console.WriteLine($"x={x} y={y}");
    }
}

using System;

static string DescribeList(int[] nums) => nums switch {
    []             => "empty",
    [var x]        => $"single: {x}",
    [var x, var y] => $"pair: {x}, {y}",
    [var first, .., var last] => $"many: starts {first}, ends {last}"
};

class Program {
    static void Main() {
        Console.WriteLine(DescribeList(new int[] {}));
        Console.WriteLine(DescribeList(new[] { 42 }));
        Console.WriteLine(DescribeList(new[] { 1, 2 }));
        Console.WriteLine(DescribeList(new[] { 1, 2, 3, 4, 5 }));
    }
}

using System;

static bool IsLetter(char c) => c is >= 'a' and <= 'z' or >= 'A' and <= 'Z';
static bool IsDigit(char c) => c is >= '0' and <= '9';
static bool IsAlphanumeric(char c) => c is var ch && (IsLetter(ch) || IsDigit(ch));

class Program {
    static void Main() {
        Console.WriteLine(IsLetter('A'));
        Console.WriteLine(IsDigit('5'));
        Console.WriteLine(IsAlphanumeric('@'));
    }
}

using System;

abstract record Shape;
record Circle(double Radius) : Shape;
record Rect(double W, double H) : Shape;
record Triangle(double Base, double Height) : Shape;

static double Area(Shape s) => s switch {
    Circle(var r)          => Math.PI * r * r,
    Rect(var w, var h)     => w * h,
    Triangle(var b, var h) => 0.5 * b * h,
    _ => throw new ArgumentException("Unknown shape")
};

class Program {
    static void Main() {
        Shape[] shapes = { new Circle(5), new Rect(4, 6), new Triangle(3, 8) };
        foreach (var s in shapes)
            Console.WriteLine($"{s.GetType().Name}: {Area(s):F2}");
    }
}
